/bin/zsh -lc "python3 - <<'PY'
from src.config.deep_merge import merge_config

base = {'app': {'port': 80, 'host': '0.0.0.0'}, 'items': [1], 'debug': False}
override = {'app': {'port': 8080}, 'items': [2, 3], 'debug': True}
base_before = {'app': {'port': 80, 'host': '0.0.0.0'}, 'items': [1], 'debug': False}
override_before = {'app': {'port': 8080}, 'items': [2, 3], 'debug': True}

merged = merge_config(base, override)
